import{_ as s,o as a,c as e,a2 as t}from"./chunks/framework.CMAFtOGK.js";const h=JSON.parse('{"title":"历年真题分类与讲解","description":"公共英语 · 历年真题分类与讲解","frontmatter":{"title":"历年真题分类与讲解","description":"公共英语 · 历年真题分类与讲解","category":"english-note"},"headers":[],"relativePath":"posts/english/notes/past-papers-guide.md","filePath":"posts/english/notes/past-papers-guide.md","lastUpdated":1784747786000}'),l={name:"posts/english/notes/past-papers-guide.md"};function i(p,n,r,o,d,c){return a(),e("div",null,[...n[0]||(n[0]=[t(`<h1 id="📑-历年真题分类与讲解" tabindex="-1">📑 历年真题分类与讲解 <a class="header-anchor" href="#📑-历年真题分类与讲解" aria-label="Permalink to &quot;📑 历年真题分类与讲解&quot;">​</a></h1><blockquote><p>广东普通专升本《公共英语》| 按年份整理 | 含答案要点与讲解<br> 写作约 100 词应用文为主 · 题型以近年大纲结构为准</p></blockquote><hr><h2 id="〇、使用说明与资料边界" tabindex="-1">〇、使用说明与资料边界 <a class="header-anchor" href="#〇、使用说明与资料边界" aria-label="Permalink to &quot;〇、使用说明与资料边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">用途</td><td style="text-align:left;">按<strong>年份</strong>回顾题型结构，重点练<strong>写作应用文</strong>；阅读/完形用「题型策略」复盘</td></tr><tr><td style="text-align:left;">写作要求</td><td style="text-align:left;"><strong>约 100 词</strong>；格式 + 要点覆盖是得分关键</td></tr><tr><td style="text-align:left;">答案性质</td><td style="text-align:left;">写作给<strong>参考范文 + 得分点讲解</strong>（非唯一标准答案）；客观题给<strong>题型解法</strong>模板</td></tr><tr><td style="text-align:left;">资料边界</td><td style="text-align:left;">完整官方卷面（含全部阅读原文）以你手头的<strong>正版真题册 / 院校公布材料</strong>为准；本笔记侧重<strong>可背结构 + 写作演练 + 年份对照</strong>，方便日常默写</td></tr></tbody></table><p><strong>题型分值（近年常见结构，以当次大纲为准）：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">题型</th><th style="text-align:right;">约分</th></tr></thead><tbody><tr><td style="text-align:left;">阅读理解</td><td style="text-align:right;">30</td></tr><tr><td style="text-align:left;">短文造句匹配</td><td style="text-align:right;">10</td></tr><tr><td style="text-align:left;">完形填空</td><td style="text-align:right;">30</td></tr><tr><td style="text-align:left;">语法填空</td><td style="text-align:right;">15</td></tr><tr><td style="text-align:left;">写作</td><td style="text-align:right;">15</td></tr><tr><td style="text-align:left;"><strong>合计</strong></td><td style="text-align:right;"><strong>100</strong></td></tr></tbody></table><p><strong>相关笔记：</strong> <a href="/zhuan-sheng-ben-notes/posts/english/notes/overview">专升本英语考试概述与题型分析</a> · 作文模板与高分句型 · 高频词汇速记 · 英语知识库</p><hr><h2 id="一、按年份-写作真题演练-核心" tabindex="-1">一、按年份：写作真题演练（核心） <a class="header-anchor" href="#一、按年份-写作真题演练-核心" aria-label="Permalink to &quot;一、按年份：写作真题演练（核心）&quot;">​</a></h2><blockquote><p>每年写作按「题目要求 → 审题要点 → 参考范文 → 得分点讲解」组织。<br> 题目若与你手头卷子措辞略有出入，以纸质卷为准，<strong>结构与得分逻辑不变</strong>。</p></blockquote><hr><h3 id="_2018-年-·-通知-notice" tabindex="-1">2018 年 · 通知（NOTICE） <a class="header-anchor" href="#_2018-年-·-通知-notice" aria-label="Permalink to &quot;2018 年 · 通知（NOTICE）&quot;">​</a></h3><p><strong>题目方向（活动通知类）：</strong><br> 学生会将举办校园文化活动（如音乐周 / 读书活动等），写一则通知，说明时间、地点、活动内容，欢迎参加。</p><p><strong>审题要点：</strong></p><ol><li>标题 NOTICE 居中</li><li>时间、地点、活动内容至少两点</li><li>欢迎参加 + 联系方式（若题干有）</li><li>右下角：The Student Union + 日期</li></ol><p><strong>参考范文（约 100 词）：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    NOTICE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>May I have your attention, please? To enrich our campus life, our school is</span></span>
<span class="line"><span>going to organize a music week.</span></span>
<span class="line"><span>The event is scheduled to be held in the school hall at 2:00 p.m. next Friday.</span></span>
<span class="line"><span>There are many exciting activities waiting for you. For one thing, you can</span></span>
<span class="line"><span>enjoy pop and folk music. For another, please bring your own instruments if</span></span>
<span class="line"><span>you wish to perform.</span></span>
<span class="line"><span>Those who are interested in it are highly welcome to participate. If you have</span></span>
<span class="line"><span>any questions, please feel free to contact us at 1234567.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                                          The Student Union</span></span>
<span class="line"><span>                                          May 10th, 2018</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p><strong>得分点讲解：</strong></p><ul><li>✅ 格式三分立：标题 / 正文 / 落款</li><li>✅ 信息齐全：what / when / where / how to join</li><li>⚠️ 漏地点或时间 → 内容分直接掉</li></ul><p><strong>默写自检：</strong> [ ] 标题 [ ] 时间地点 [ ] 两项活动细节 [ ] 欢迎句 [ ] 落款</p><hr><h3 id="_2019-年-·-邀请信" tabindex="-1">2019 年 · 邀请信 <a class="header-anchor" href="#_2019-年-·-邀请信" aria-label="Permalink to &quot;2019 年 · 邀请信&quot;">​</a></h3><p><strong>题目方向：</strong><br> 邀请外国朋友 Peter（或同学）参加学校「中国传统文化展」或同类活动，说明时间、可体验项目、意义。</p><p><strong>审题要点：</strong></p><ol><li>Dear + 名；落款 Li Hua</li><li>写信目的一句清</li><li>时间 / 可做之事 / 意义或期待</li><li>盼复</li></ol><p><strong>参考范文：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dear Peter,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>How is everything going? I am writing this letter to express my earnest hope</span></span>
<span class="line"><span>to invite you to visit the exhibition of Traditional Chinese Culture in our school.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Here are some relevant details about this matter. First and foremost, the</span></span>
<span class="line"><span>exhibition will be held in the school hall at 2:00 p.m. next Friday.</span></span>
<span class="line"><span>Furthermore, you can experience the art of paper-cutting yourself.</span></span>
<span class="line"><span>Last but not least, it will be a meaningful and unforgettable experience.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Taking all these factors into consideration, I sincerely hope you can accept</span></span>
<span class="line"><span>my invitation. I am looking forward to hearing from you soon.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Yours sincerely,</span></span>
<span class="line"><span>Li Hua</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><p><strong>得分点讲解：</strong></p><ul><li>✅ 邀请目的明确</li><li>✅ 细节有「时间 + 体验」比空喊 meaningful 更重要</li><li>⚠️ 朋友信可用 How is everything going?；正式申请信可改为 I am writing to...</li></ul><p><strong>默写自检：</strong> [ ] 称呼落款 [ ] 目的 [ ] 三点细节 [ ] 期许盼复</p><hr><h3 id="_2020-年-·-申请信" tabindex="-1">2020 年 · 申请信 <a class="header-anchor" href="#_2020-年-·-申请信" aria-label="Permalink to &quot;2020 年 · 申请信&quot;">​</a></h3><p><strong>题目方向：</strong><br> 申请学生会某职位 / 英语社团干事 / 志愿者，说明自身条件与能做什么。</p><p><strong>审题要点：</strong></p><ol><li>申请对象与职位</li><li>自身优势 2–3 点（经验、技能、性格）</li><li>恳请给予机会</li></ol><p><strong>参考范文：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dear Mr. Smith,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I am writing this letter to express my earnest hope to apply for the position</span></span>
<span class="line"><span>of English tutor in the Student Union.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Here are some relevant details about this matter. First and foremost, I have</span></span>
<span class="line"><span>been learning English for many years and once won a speech contest.</span></span>
<span class="line"><span>Furthermore, I am patient and good at communicating with others.</span></span>
<span class="line"><span>Last but not least, I am willing to spare time to serve my schoolmates.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I sincerely hope you can give me an opportunity. I am looking forward to</span></span>
<span class="line"><span>hearing from you soon.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Yours sincerely,</span></span>
<span class="line"><span>Li Hua</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><p><strong>得分点讲解：</strong></p><ul><li>✅ apply for the position of... 是申请信标志句</li><li>✅ 每点对应「能力/经历」，避免空喊 hard-working</li><li>⚠️ 题干若给截止时间，必须写入</li></ul><hr><h3 id="_2021-年-·-建议信-感谢信-二选一练" tabindex="-1">2021 年 · 建议信 / 感谢信（二选一练） <a class="header-anchor" href="#_2021-年-·-建议信-感谢信-二选一练" aria-label="Permalink to &quot;2021 年 · 建议信 / 感谢信（二选一练）&quot;">​</a></h3><h4 id="a-建议信方向" tabindex="-1">A. 建议信方向 <a class="header-anchor" href="#a-建议信方向" aria-label="Permalink to &quot;A. 建议信方向&quot;">​</a></h4><p>就「如何提高英语」或「校园生活某一问题」给同学/校长提建议。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dear Mark,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I am writing this letter to offer some suggestions on how to improve your English.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>First and foremost, you had better read English newspapers every day.</span></span>
<span class="line"><span>Furthermore, practicing speaking with classmates is highly beneficial.</span></span>
<span class="line"><span>Last but not least, reviewing new words regularly will help you a lot.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I sincerely hope these suggestions will be useful to you.</span></span>
<span class="line"><span>I am looking forward to hearing from you soon.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Yours sincerely,</span></span>
<span class="line"><span>Li Hua</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h4 id="b-感谢信方向" tabindex="-1">B. 感谢信方向 <a class="header-anchor" href="#b-感谢信方向" aria-label="Permalink to &quot;B. 感谢信方向&quot;">​</a></h4><p>感谢老师/朋友在学习或生活上的帮助。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dear Mr. Smith,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I am writing this letter to express my sincere thanks for your help during my</span></span>
<span class="line"><span>preparation for the English exam.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>First and foremost, you explained the difficult grammar points patiently.</span></span>
<span class="line"><span>Furthermore, the materials you recommended were extremely useful.</span></span>
<span class="line"><span>Last but not least, your encouragement gave me great confidence.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I would be highly appreciative if I could repay your kindness someday.</span></span>
<span class="line"><span>I am looking forward to seeing you again.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Yours sincerely,</span></span>
<span class="line"><span>Li Hua</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p><strong>得分点讲解：</strong></p><ul><li>建议信用 <strong>offer some suggestions on...</strong></li><li>感谢信用 <strong>express my sincere thanks for...</strong> + 具体帮助事例</li><li>两类都忌只有套话、没有「具体做了什么」</li></ul><hr><h3 id="_2022-年-·-道歉信-通知-二选一练" tabindex="-1">2022 年 · 道歉信 / 通知（二选一练） <a class="header-anchor" href="#_2022-年-·-道歉信-通知-二选一练" aria-label="Permalink to &quot;2022 年 · 道歉信 / 通知（二选一练）&quot;">​</a></h3><h4 id="a-道歉信方向" tabindex="-1">A. 道歉信方向 <a class="header-anchor" href="#a-道歉信方向" aria-label="Permalink to &quot;A. 道歉信方向&quot;">​</a></h4><p>因故不能赴约/迟交作业/弄丢物品，说明原因并提出补救。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dear Peter,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I am writing this letter to apologize for not being able to attend your</span></span>
<span class="line"><span>birthday party last Saturday.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>First and foremost, I had to look after my sick mother in the hospital.</span></span>
<span class="line"><span>Furthermore, I should have informed you earlier, and I am truly sorry.</span></span>
<span class="line"><span>Last but not least, I would like to invite you to dinner next weekend to make</span></span>
<span class="line"><span>up for it.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I sincerely hope you can accept my apology.</span></span>
<span class="line"><span>I am looking forward to your reply.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Yours sincerely,</span></span>
<span class="line"><span>Li Hua</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h4 id="b-通知方向-运动会-演讲比赛" tabindex="-1">B. 通知方向（运动会 / 演讲比赛） <a class="header-anchor" href="#b-通知方向-运动会-演讲比赛" aria-label="Permalink to &quot;B. 通知方向（运动会 / 演讲比赛）&quot;">​</a></h4><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    NOTICE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>To enrich our campus life, the Student Union is going to organize an English</span></span>
<span class="line"><span>speech contest.</span></span>
<span class="line"><span>It will take place in the school hall at 3:00 p.m. on Nov. 20th.</span></span>
<span class="line"><span>For one thing, the topic is &quot;My College Life&quot;. For another, each speaker will</span></span>
<span class="line"><span>have five minutes.</span></span>
<span class="line"><span>Those who are interested are highly welcome to participate. Please contact us</span></span>
<span class="line"><span>at 1234567 for registration.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                                          The Student Union</span></span>
<span class="line"><span>                                          Nov. 5th, 2022</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p><strong>得分点讲解：</strong></p><ul><li>道歉信结构：<strong>道歉 → 原因 → 补救 → 再致歉</strong></li><li>通知：<strong>活动名 + 时间地点 + 规则/内容 + 欢迎报名</strong></li></ul><hr><h3 id="_2023-年-·-推荐信-邀请信" tabindex="-1">2023 年 · 推荐信 / 邀请信 <a class="header-anchor" href="#_2023-年-·-推荐信-邀请信" aria-label="Permalink to &quot;2023 年 · 推荐信 / 邀请信&quot;">​</a></h3><p><strong>题目方向：</strong><br> 向朋友推荐一本书/一门课/一次校园活动，或邀请参加志愿者活动。</p><p><strong>推荐信范文：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dear Mark,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>How is everything going? I am writing this letter to recommend a book called</span></span>
<span class="line"><span>&quot;The Old Man and the Sea&quot; to you.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>First and foremost, the story is simple but inspiring.</span></span>
<span class="line"><span>Furthermore, the language is not too difficult for us to understand.</span></span>
<span class="line"><span>Last but not least, it will help you build a positive attitude toward challenges.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I sincerely hope you will enjoy reading it.</span></span>
<span class="line"><span>I am looking forward to discussing it with you soon.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Yours sincerely,</span></span>
<span class="line"><span>Li Hua</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p><strong>得分点讲解：</strong></p><ul><li>recommend A to B</li><li>至少两点「为什么值得」+ 一句期待反馈</li></ul><hr><h3 id="_2024-年-·-综合应用-邀请-活动通知" tabindex="-1">2024 年 · 综合应用（邀请 / 活动通知） <a class="header-anchor" href="#_2024-年-·-综合应用-邀请-活动通知" aria-label="Permalink to &quot;2024 年 · 综合应用（邀请 / 活动通知）&quot;">​</a></h3><p><strong>题目方向（近年常见综合）：</strong><br> 学校举办「传统文化周」或「职业规划讲座」，写邀请信或 NOTICE，覆盖时间、地点、内容、对象。</p><p><strong>邀请信精简版（约 100 词）：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dear Peter,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I am writing to invite you to the Traditional Chinese Culture Week in our school.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>First of all, it will be held in the school hall from 2:00 p.m. to 5:00 p.m.</span></span>
<span class="line"><span>next Friday. In addition, you can try paper-cutting and watch calligraphy shows.</span></span>
<span class="line"><span>What is more, it will help you better understand Chinese culture.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I sincerely hope you can come. I am looking forward to your early reply.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Yours sincerely,</span></span>
<span class="line"><span>Li Hua</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p><strong>得分点讲解：</strong></p><ul><li>2024 起更看重<strong>信息密度</strong>：时间段、项目、意义各一句即可</li><li>套话重复（hope + appreciative 连用）可只留一句，把词数留给要点</li></ul><hr><h3 id="_2025–2026-备考预测-非真题-按趋势" tabindex="-1">2025–2026 备考预测（非真题，按趋势） <a class="header-anchor" href="#_2025–2026-备考预测-非真题-按趋势" aria-label="Permalink to &quot;2025–2026 备考预测（非真题，按趋势）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">更可能</th><th style="text-align:left;">相对少见</th></tr></thead><tbody><tr><td style="text-align:left;">邀请信、申请信、感谢信、道歉信、建议信</td><td style="text-align:left;">长议论文、图表作文</td></tr><tr><td style="text-align:left;">NOTICE（讲座/比赛/志愿活动）</td><td style="text-align:left;">纯记叙文</td></tr><tr><td style="text-align:left;">中文要点提示 → 英文应用文</td><td style="text-align:left;">全英文长题干无要点</td></tr></tbody></table><p><strong>冲刺策略：</strong> 只精背 作文模板与高分句型 中的<strong>书信 + NOTICE</strong>，每周限时默写 2 篇。</p><hr><h2 id="二、按年份-客观题怎么复盘-统一方法" tabindex="-1">二、按年份：客观题怎么复盘（统一方法） <a class="header-anchor" href="#二、按年份-客观题怎么复盘-统一方法" aria-label="Permalink to &quot;二、按年份：客观题怎么复盘（统一方法）&quot;">​</a></h2><p>完整阅读/完形原文以纸质真题为准。这里给<strong>跨年份通用解题卡</strong>，做完一套就按此填坑。</p><h3 id="_1-阅读理解-约-30-分" tabindex="-1">1. 阅读理解（约 30 分） <a class="header-anchor" href="#_1-阅读理解-约-30-分" aria-label="Permalink to &quot;1. 阅读理解（约 30 分）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">题型</th><th style="text-align:left;">做法</th><th style="text-align:left;">常见坑</th></tr></thead><tbody><tr><td style="text-align:left;">细节题</td><td style="text-align:left;">题干关键词回原文定位，同义改写选答案</td><td style="text-align:left;">凭印象选「好像提过」</td></tr><tr><td style="text-align:left;">主旨题</td><td style="text-align:left;">首段 + 各段首句，排除过宽/过窄</td><td style="text-align:left;">选细节当主旨</td></tr><tr><td style="text-align:left;">猜词题</td><td style="text-align:left;">上下文逻辑 + 并列/转折</td><td style="text-align:left;">只看词形像不像</td></tr><tr><td style="text-align:left;">推断题</td><td style="text-align:left;">原文能推出一层，不脑补两层</td><td style="text-align:left;">过度推理</td></tr><tr><td style="text-align:left;">态度题</td><td style="text-align:left;">抓评价性形容词与转折后观点</td><td style="text-align:left;">把作者观点当某人物观点</td></tr></tbody></table><p><strong>年份复盘表（自己填）：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:center;">错几题</th><th style="text-align:left;">主错题型</th><th style="text-align:left;">生词/长句</th><th style="text-align:left;">下次动作</th></tr></thead><tbody><tr><td style="text-align:left;">2018</td><td style="text-align:center;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">2019</td><td style="text-align:center;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">2020</td><td style="text-align:center;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">2021</td><td style="text-align:center;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">2022</td><td style="text-align:center;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">2023</td><td style="text-align:center;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">2024</td><td style="text-align:center;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td></tr></tbody></table><h3 id="_2-完形填空-约-30-分" tabindex="-1">2. 完形填空（约 30 分） <a class="header-anchor" href="#_2-完形填空-约-30-分" aria-label="Permalink to &quot;2. 完形填空（约 30 分）&quot;">​</a></h3><p><strong>三步：</strong></p><ol><li>通读知大意（记叙/说明）</li><li>先易后难：搭配与语法优先</li><li>填完复读查逻辑是否通</li></ol><p><strong>高频考点：</strong> 动词短语、近义词、连词、指代、固定搭配（见 高频词汇速记）</p><h3 id="_3-语法填空-约-15-分" tabindex="-1">3. 语法填空（约 15 分） <a class="header-anchor" href="#_3-语法填空-约-15-分" aria-label="Permalink to &quot;3. 语法填空（约 15 分）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">空型</th><th style="text-align:left;">想什么</th></tr></thead><tbody><tr><td style="text-align:left;">动词</td><td style="text-align:left;">时态 / 语态 / 非谓语 / 主谓一致</td></tr><tr><td style="text-align:left;">名词</td><td style="text-align:left;">单复数 / 词性转换</td></tr><tr><td style="text-align:left;">形副</td><td style="text-align:left;">比较级最高级 / 词性</td></tr><tr><td style="text-align:left;">介词</td><td style="text-align:left;">固定搭配</td></tr><tr><td style="text-align:left;">冠词</td><td style="text-align:left;">a/an/the / 零冠词</td></tr><tr><td style="text-align:left;">连词/从句</td><td style="text-align:left;">缺什么成分填什么关系词</td></tr></tbody></table><h3 id="_4-短文造句匹配-约-10-分" tabindex="-1">4. 短文造句匹配（约 10 分） <a class="header-anchor" href="#_4-短文造句匹配-约-10-分" aria-label="Permalink to &quot;4. 短文造句匹配（约 10 分）&quot;">​</a></h3><ul><li>看空前空后：指代（this/these）、逻辑（however/therefore）、词汇复现</li><li>先定逻辑关系再选句，勿逐句翻译硬塞</li></ul><hr><h2 id="三、按题型总表-写作体裁频率-·-备考用" tabindex="-1">三、按题型总表（写作体裁频率 · 备考用） <a class="header-anchor" href="#三、按题型总表-写作体裁频率-·-备考用" aria-label="Permalink to &quot;三、按题型总表（写作体裁频率 · 备考用）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">体裁</th><th style="text-align:left;">出现倾向</th><th style="text-align:center;">优先级</th></tr></thead><tbody><tr><td style="text-align:left;">邀请信</td><td style="text-align:left;">高</td><td style="text-align:center;">★★★★★</td></tr><tr><td style="text-align:left;">通知 NOTICE</td><td style="text-align:left;">高</td><td style="text-align:center;">★★★★★</td></tr><tr><td style="text-align:left;">申请信</td><td style="text-align:left;">高</td><td style="text-align:center;">★★★★★</td></tr><tr><td style="text-align:left;">感谢 / 道歉 / 建议 / 推荐</td><td style="text-align:left;">中高</td><td style="text-align:center;">★★★★</td></tr><tr><td style="text-align:left;">投诉信</td><td style="text-align:left;">中</td><td style="text-align:center;">★★★</td></tr><tr><td style="text-align:left;">议论文 / 图表</td><td style="text-align:left;">低（广东极少）</td><td style="text-align:center;">★</td></tr></tbody></table><hr><h2 id="四、答案讲解总原则-写作评分思维" tabindex="-1">四、答案讲解总原则（写作评分思维） <a class="header-anchor" href="#四、答案讲解总原则-写作评分思维" aria-label="Permalink to &quot;四、答案讲解总原则（写作评分思维）&quot;">​</a></h2><p>阅卷大致看：</p><ol><li><strong>格式</strong>（称呼、落款、NOTICE 标题与右下角）</li><li><strong>要点是否写全</strong>（题干几条就对应几句）</li><li><strong>语言是否基本正确</strong>（时态、主谓、拼写）</li><li><strong>是否约 100 词、条理清楚</strong></li></ol><table tabindex="0"><thead><tr><th style="text-align:left;">档位（满分 15 粗分）</th><th style="text-align:left;">特征</th></tr></thead><tbody><tr><td style="text-align:left;">12–15</td><td style="text-align:left;">格式对、要点全、少量小错、表达清楚</td></tr><tr><td style="text-align:left;">9–11</td><td style="text-align:left;">要点基本全，有些语法错或略空</td></tr><tr><td style="text-align:left;">6–8</td><td style="text-align:left;">漏要点 / 格式残缺 / 中式堆砌</td></tr><tr><td style="text-align:left;">0–5</td><td style="text-align:left;">体裁偏题、几乎无法理解</td></tr></tbody></table><hr><h2 id="五、刷题节奏建议" tabindex="-1">五、刷题节奏建议 <a class="header-anchor" href="#五、刷题节奏建议" aria-label="Permalink to &quot;五、刷题节奏建议&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每周：</span></span>
<span class="line"><span>  - 1 套客观题（限时，按第二节复盘表填坑）</span></span>
<span class="line"><span>  - 2 篇写作默写（书信 1 + 通知 1，25 分钟内）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每月：</span></span>
<span class="line"><span>  - 对照本笔记「年份写作」轮换体裁</span></span>
<span class="line"><span>  - 生词进 高频词汇速记 主题包</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><hr><h2 id="秒杀口诀" tabindex="-1">秒杀口诀 <a class="header-anchor" href="#秒杀口诀" aria-label="Permalink to &quot;秒杀口诀&quot;">​</a></h2><blockquote><p><strong>真题按年看体裁，书信通知反复练</strong><br><strong>客观题型定方法，错题填表不二刷空</strong><br><strong>范文只是得分样，要点写全才是王</strong></p></blockquote><hr><h2 id="相关笔记" tabindex="-1">相关笔记 <a class="header-anchor" href="#相关笔记" aria-label="Permalink to &quot;相关笔记&quot;">​</a></h2><ul><li>作文模板与高分句型</li><li>高频词汇速记</li><li><a href="/zhuan-sheng-ben-notes/posts/english/notes/overview">专升本英语考试概述与题型分析</a></li><li>语法考点精讲</li><li>阅读理解高分技巧</li><li>英语知识库</li></ul>`,109)])])}const u=s(l,[["render",i]]);export{h as __pageData,u as default};
